/**
 * Protoss game data.
 *
 * ┌───────────────────────────────────────────────────────────────────────┐
 * │  Costs, supply, and build times below are taken from SC2's OWN game     │
 * │  data (the data.json generated by BurnySc2/sc2-techtree, the same file  │
 * │  BuRny's planner uses). That snapshot is current to patch 5.0.16         │
 * │  (verified: it already carries Nexus supply = 13, the 5.0.16 value).    │
 * │                                                                         │
 * │  TIME UNIT: build times are in FASTER-clock seconds — the value the     │
 * │  in-game timer shows and that build orders quote. The raw game data     │
 * │  stores Normal-speed seconds; Faster = raw / 1.4 (Probe 17 -> 12.1).    │
 * │  Verified against known values: Probe 12, Gateway 46, Nexus 71. Income  │
 * │  rates use the same Faster clock.                                        │
 * │                                                                         │
 * │  Confirmed 5.0.16 economy overrides: startingWorkers 12->8, Nexus       │
 * │  supply 15->13. Chrono Boost: 50 energy, +50% for 20s; Nexus starts     │
 * │  50 energy, 200 max, regen 0.5625/s.                                     │
 * │                                                                         │
 * │  ⚠️ Still calibration targets (NOT in the game data — they come from     │
 * │  mining behavior): mineralRate*, gasRatePerWorker, probeBuildOccupancy.  │
 * │  Tune these against headless SC2 (see README "Validation").              │
 * └───────────────────────────────────────────────────────────────────────┘
 */
function ent(name, minerals, gas, buildTime, producer, opts = {}) {
    // Defaults first, then spread opts so ALL optional fields (moveSpeed,
    // morphFrom, isUpgrade, warpCooldown, isWorker, ...) carry through.
    return {
        name,
        minerals,
        gas,
        buildTime,
        producer,
        supplyCost: 0,
        supplyProvided: 0,
        requires: [],
        isStructure: false,
        ...opts,
    };
}
const entities = {};
function add(e) {
    entities[e.name] = e;
}
// Build times are Faster-clock seconds (raw game data / 1.4). See header.
// --- Structures ---------------------------------------------------------
add(ent("Nexus", 400, 0, 71.4, "Probe", { supplyProvided: 13, isStructure: true }));
add(ent("Pylon", 100, 0, 17.9, "Probe", { supplyProvided: 8, isStructure: true }));
add(ent("Assimilator", 75, 0, 21.4, "Probe", { isStructure: true }));
add(ent("Gateway", 150, 0, 46.4, "Probe", { isStructure: true, requires: ["Pylon"] }));
add(ent("CyberneticsCore", 150, 0, 35.7, "Probe", { isStructure: true, requires: ["Gateway"] }));
add(ent("Forge", 150, 0, 32.1, "Probe", { isStructure: true, requires: ["Pylon"] }));
add(ent("TwilightCouncil", 150, 100, 35.7, "Probe", { isStructure: true, requires: ["CyberneticsCore"] }));
add(ent("Stargate", 150, 150, 42.9, "Probe", { isStructure: true, requires: ["CyberneticsCore"] }));
add(ent("RoboticsFacility", 150, 100, 46.4, "Probe", { isStructure: true, requires: ["CyberneticsCore"] }));
// --- Warp Gate tech ------------------------------------------------------
// Warp Gate research is at the Cybernetics Core (the 5.0.16 PTR briefly moved it
// to the Gateway; that was reverted in the live hotfixes). A Warp Gate is a
// Gateway morphed in place (~7s). Once you have Warp Gates and a powered Pylon,
// you WARP units in there (~4s) — planting a proxy Pylon near the enemy delivers
// the army at the front instead of walking it across the map.
add(ent("WarpGateResearch", 50, 50, 100, "CyberneticsCore", { isUpgrade: true, requires: ["CyberneticsCore"] }));
add(ent("WarpGate", 25, 25, 7, "Gateway", { isStructure: true, morphFrom: "Gateway", requires: ["WarpGateResearch"] }));
// --- Nexus-produced -----------------------------------------------------
add(ent("Probe", 50, 0, 12.1, "Nexus", { supplyCost: 1, isWorker: true, moveSpeed: 2.8125 }));
// --- Gateway units (warpCooldown ~ build time - 7s, per Liquipedia) -------
// Adept pre-warpgate build time bumped 30 -> 33 by the 5.0.16 hotfix.
//
// ⚠️ dps/hp/shields below are standard baseline (NO upgrades, no bonus-vs-
// armor/light) LotV-era figures, for ranking builds by unitValue() — NOT
// verified against 5.0.16 game data the way cost/buildTime are. Combat
// abilities (Blink, Guardian Shield, Pulsar Beam ramp, ...) are not
// modeled at all yet; dps is the raw autoattack only.
add(ent("Zealot", 100, 0, 27.1, "Gateway", { supplyCost: 2, moveSpeed: 2.25, warpCooldown: 20, dps: 18.6, hp: 100, shields: 50 }));
add(ent("Stalker", 125, 50, 27.1, "Gateway", { supplyCost: 2, moveSpeed: 2.9531, warpCooldown: 20, requires: ["CyberneticsCore"], dps: 9.7, hp: 100, shields: 80 }));
add(ent("Adept", 100, 25, 33.0, "Gateway", { supplyCost: 2, moveSpeed: 2.5, warpCooldown: 26, requires: ["CyberneticsCore"], dps: 6.2, hp: 70, shields: 70 }));
add(ent("Sentry", 50, 100, 23.3, "Gateway", { supplyCost: 2, moveSpeed: 2.5, warpCooldown: 20.3, requires: ["CyberneticsCore"], dps: 8.4, hp: 40, shields: 40 }));
// --- Stargate units -----------------------------------------------------
add(ent("Oracle", 150, 150, 37.1, "Stargate", { supplyCost: 3, moveSpeed: 4.0, dps: 16.7, hp: 100, shields: 60 }));
add(ent("VoidRay", 250, 150, 43.0, "Stargate", { supplyCost: 4, moveSpeed: 2.75, dps: 16.8, hp: 150, shields: 100 }));
// --- Robotics units -----------------------------------------------------
add(ent("Immortal", 250, 100, 39.3, "RoboticsFacility", { supplyCost: 4, moveSpeed: 2.25, dps: 19.2, hp: 200, shields: 100 }));
// Observer has no weapon (pure scout/detector) — dps 0, contributes no
// fighting VALUE by design, even though it has real strategic value.
add(ent("Observer", 25, 75, 17.9, "RoboticsFacility", { supplyCost: 1, moveSpeed: 2.0156, hp: 40, shields: 20 }));
export const PROTOSS = {
    patch: "5.0.16",
    race: "Protoss",
    economy: {
        startingWorkers: 8, // 5.0.16: was 12
        startingMinerals: 50,
        startingGas: 0,
        mineralPatchesPerBase: 8,
        gasGeysersPerBase: 2,
        // Mineral rates (min/sec per worker). STRUCTURE from the "Treatise on the
        // Economy of SCII" (tl.net/forum/legacy-of-the-void/482775): income is linear
        // to the 16th worker with the 1st and 2nd worker on a patch mining EQUALLY;
        // the 3rd worker (oversaturation) is ~half.
        //   The treatise's absolute figure is 42 min/min (0.70/s) — but that's the
        //   HotS saturated average. LotV's economy is faster, and pro early-game
        //   (close patches + hand-mining) is faster still: the published 5.0.16 builds
        //   only match at ~55 min/min (at 0.70 the sim is 24s off; see git history).
        //   So we use the ground-truth-calibrated ~0.925/s, scaled by miningMicro.
        mineralRateFirstWorker: 0.925, // ~55/min
        mineralRateSecondWorker: 0.925, // ~55/min (equal to 1st, per the treatise)
        mineralRateThirdWorker: 0.33, // ~20/min, 3rd worker (oversaturation)
        miningMicro: 1.0, // 1.0 = pro hand-mining; ~0.9 = a-move ladder play
        gasRatePerWorker: 0.63, // ~38/min, up to 3 per assimilator (not yet calibrated)
        // Chrono Boost / Nexus energy (confirmed LotV):
        nexusStartEnergy: 50,
        nexusMaxEnergy: 200,
        nexusEnergyRegen: 0.5625,
        chronoCost: 50,
        chronoBoostWindow: 20,
        chronoSpeedMultiplier: 1.5,
        probeBuildOccupancy: 4, // seconds a probe is off minerals to start a structure
        warpInTime: 4, // 5.0.16 standardized warp-in (old 11.4s proxy penalty removed)
    },
    entities,
};
